// معالج Kommo Webhooks - النسخة المؤسسية المُحسّنة
// ================================================
// Version: 4.0 - محدث لمعالجة جميع أنواع الأحداث بشكل صحيح

// ==================
// الإعدادات
// ==================
const CONFIG = {
  TIME_WINDOW: 30,           // نافذة زمنية بالثواني لتجميع النبضات
  MESSAGE_CACHE_TTL: 120000, // مدة الاحتفاظ بالكاش (2 دقيقة)
  MAX_EVENTS_PER_MESSAGE: 10, // حد أقصى للنبضات لكل رسالة
  MAX_CACHE_SIZE: 5000,       // حد أقصى لحجم الكاش
  DEBUG_MODE: true           // تفعيل وضع Debug
};

// ==================
// تهيئة الذاكرة المؤقتة
// ==================
const staticData = $getWorkflowStaticData('global');
if (!staticData.messageCache) {
  staticData.messageCache = {};
  staticData.processedMessages = {};
  staticData.lastCleanup = Date.now();
  staticData.cacheSize = 0;
}

// ==================
// دوال مساعدة
// ==================

// دالة للطباعة الآمنة في debug mode
function debugLog(...args) {
  if (CONFIG.DEBUG_MODE) {
    console.log(...args);
  }
}

// دالة لاستخراج القيمة من المفاتيح المسطحة
function extractFlatValue(obj, ...keys) {
  for (const key of keys) {
    if (obj[key] !== undefined && obj[key] !== null && obj[key] !== '') {
      return obj[key];
    }
  }
  return '';
}

// دالة لتنظيف وإدارة حجم الكاش
function cleanupCache() {
  const now = Date.now();

  // تنظيف دوري كل دقيقة
  if (now - staticData.lastCleanup > 60000) {
    let removedCount = 0;

    // حذف العناصر المنتهية
    for (const key in staticData.messageCache) {
      if (now - staticData.messageCache[key].timestamp > CONFIG.MESSAGE_CACHE_TTL) {
        delete staticData.messageCache[key];
        removedCount++;
      }
    }

    for (const key in staticData.processedMessages) {
      if (now - staticData.processedMessages[key] > CONFIG.MESSAGE_CACHE_TTL) {
        delete staticData.processedMessages[key];
      }
    }

    // تحديد حجم الكاش
    staticData.cacheSize = Object.keys(staticData.messageCache).length;

    // إذا تجاوز الحد الأقصى، احذف الأقدم
    if (staticData.cacheSize > CONFIG.MAX_CACHE_SIZE) {
      const entries = Object.entries(staticData.messageCache)
        .sort((a, b) => a[1].timestamp - b[1].timestamp);

      const toRemove = entries.slice(0, staticData.cacheSize - CONFIG.MAX_CACHE_SIZE);
      toRemove.forEach(([key]) => {
        delete staticData.messageCache[key];
        removedCount++;
      });
    }

    staticData.lastCleanup = now;
    debugLog(`Cache cleanup: removed ${removedCount} items, current size: ${staticData.cacheSize}`);
  }
}

// دالة لتصنيف نوع الحدث
function classifyEvent(body) {
  const keys = Object.keys(body || {});
  const has = (prefix) => keys.some(k => k.startsWith(prefix));

  const eventTypes = [
    { check: 'message[add]', type: 'message[add]', priority: 10, category: 'message', expectedPulses: 9 },
    { check: 'unsorted[add]', type: 'unsorted[add]', priority: 8, category: 'lead_creation', expectedPulses: 6 },
    { check: 'talk[add]', type: 'talk[add]', priority: 6, category: 'conversation', expectedPulses: 4 },
    { check: 'talk[update]', type: 'talk[update]', priority: 5, category: 'conversation', expectedPulses: 3 },
    { check: 'leads[update]', type: 'leads[update]', priority: 4, category: 'lead_management', expectedPulses: 2 },
    { check: 'leads[delete]', type: 'leads[delete]', priority: 1, category: 'deletion', expectedPulses: 1 },
    { check: 'contacts[update]', type: 'contacts[update]', priority: 3, category: 'contact_management', expectedPulses: 2 }
  ];

  for (const eventType of eventTypes) {
    if (has(eventType.check)) {
      return {
        event_type: eventType.type,
        priority: eventType.priority,
        category: eventType.category,
        expected_pulses: Math.min(eventType.expectedPulses, CONFIG.MAX_EVENTS_PER_MESSAGE)
      };
    }
  }

  return { event_type: 'unknown', priority: 0, category: 'other', expected_pulses: 1 };
}

// دالة لإنشاء معرف فريد قوي
function generateFingerprint(data) {
  const {
    message_id = '',
    chat_id = '',
    lead_id = '',
    source = '',
    created_at = '',
    text_snippet = '',
    event_type = ''
  } = data;

  // إذا كان هناك message_id فهو الأفضل
  if (message_id) return message_id;

  // بناء معرف مركب
  const timeSlot = Math.floor(Date.now() / 1000 / CONFIG.TIME_WINDOW);
  const parts = [
    chat_id || 'no-chat',
    lead_id || 'no-lead',
    source || event_type || 'unknown',
    timeSlot,
    text_snippet ? text_snippet.substring(0, 10).replace(/\s/g, '') : 'no-text'
  ];

  return parts.filter(p => p).join('_');
}

// دالة لتطبيع الطوابع الزمنية
function normalizeTimestamp(rawTs) {
  if (!rawTs) return '';

  const num = Number(rawTs);
  if (isNaN(num)) return '';

  // إذا كان الرقم كبير جداً، ربما يكون milliseconds
  if (num > 9999999999) {
    return String(Math.floor(num / 1000));
  }

  return String(num);
}

// دالة محسنة لاستخراج النص من جميع الأحداث
function extractMessageText(body, eventType) {
  let text = '';

  // محاولات متعددة لاستخراج النص حسب نوع الحدث
  if (eventType === 'message[add]') {
    text = extractFlatValue(body,
      'message[add][0][text]',
      'message[add][0][message]',
      'message[add][0][body]'
    );
  } else if (eventType === 'talk[update]') {
    text = extractFlatValue(body,
      'talk[update][0][last_message]',
      'talk[update][0][text]',
      'talk[update][0][message]',
      'talk[update][0][body]'
    );
  } else if (eventType === 'talk[add]') {
    text = extractFlatValue(body,
      'talk[add][0][last_message]',
      'talk[add][0][text]',
      'talk[add][0][message]'
    );
  } else if (eventType === 'unsorted[add]') {
    text = extractFlatValue(body,
      'unsorted[add][0][source_data][data][0][text]',
      'unsorted[add][0][text]',
      'unsorted[add][0][message]',
      'unsorted[add][0][body]'
    );
  } else if (eventType === 'leads[update]') {
    // البحث في الحقول المخصصة للـ leads
    text = extractFlatValue(body,
      'leads[update][0][text]',
      'leads[update][0][last_message]',
      'leads[update][0][note]',
      'leads[update][0][message]'
    );

    // البحث في custom fields
    if (!text) {
      for (let i = 0; i < 10; i++) {
        for (let j = 0; j < 5; j++) {
          const customFieldPath = `leads[update][0][custom_fields_values][${i}][values][${j}][value]`;
          if (body[customFieldPath]) {
            const value = body[customFieldPath];
            // تحقق أن القيمة تبدو كنص وليست رقم أو ID
            if (typeof value === 'string' && value.length > 2 && !(/^\d+$/.test(value))) {
              text = value;
              debugLog(`Found text in custom field: ${customFieldPath}`);
              break;
            }
          }
        }
        if (text) break;
      }
    }
  }

  return text;
}

// ==================
// معالج الأحداث الرئيسي
// ==================

// تنظيف الكاش أولاً
cleanupCache();

// استرجاع المجموعات من الكاش السابق
const eventGroups = {};

// التحقق من الكاش الموجود واسترجاع المجموعات غير المكتملة
for (const [key, cachedGroup] of Object.entries(staticData.messageCache)) {
  if (!cachedGroup.is_complete) {
    eventGroups[key] = {
      ...cachedGroup,
      unique_events: new Set(cachedGroup.unique_events_array || [])
    };
    debugLog(`Restored incomplete group from cache: ${key}`);
  }
}

// معالجة كل نبضة واردة
items.forEach((item, index) => {
  const j = item.json || {};
  const b = j.body || {};

  debugLog(`\n=== Processing Event ${index + 1} ===`);
  debugLog("Body keys sample:", Object.keys(b).slice(0, 10));

  const classification = classifyEvent(b);
  debugLog("Event classification:", classification);

  // تجاهل أحداث الحذف
  if (classification.category === 'deletion') {
    debugLog("Ignoring deletion event");
    return;
  }

  // ==================
  // استخراج البيانات من المفاتيح المسطحة
  // ==================

  // استخراج lead_id
  const lead_id = extractFlatValue(b,
    'leads[update][0][id]',
    'talk[update][0][entity_id]',
    'talk[add][0][entity_id]',
    'unsorted[add][0][lead_id]',
    'message[add][0][entity_id]',
    'message[add][0][element_id]'
  );

  // استخراج chat_id
  const chat_id = extractFlatValue(b,
    'message[add][0][chat_id]',
    'talk[add][0][chat_id]',
    'talk[update][0][chat_id]',
    'unsorted[add][0][source_data][origin][chat_id]',
    'leads[update][0][chat_id]'
  );

  // استخراج message_id
  const message_id = extractFlatValue(b,
    'message[add][0][id]',
    'unsorted[add][0][source_data][data][0][id]',
    'leads[update][0][message_id]',
    'talk[update][0][message_id]'
  );

  // استخراج النص باستخدام الدالة المحسنة
  const message_text = extractMessageText(b, classification.event_type);

  debugLog("Extracted text:", message_text || "NO TEXT FOUND");

  // استخراج اسم العميل
  const client_name = extractFlatValue(b,
    'message[add][0][author][name]',
    'unsorted[add][0][source_data][client][name]',
    'unsorted[add][0][source_data][from]',
    'unsorted[add][0][source_data][name]',
    'contacts[add][0][name]',
    'contacts[update][0][name]',
    'leads[update][0][contact_name]'
  );

  // استخراج معلومات إضافية
  const pipeline_id = extractFlatValue(b,
    'leads[update][0][pipeline_id]',
    'unsorted[add][0][pipeline_id]'
  );

  const status_id = extractFlatValue(b,
    'leads[update][0][status_id]',
    'unsorted[add][0][status_id]'
  );

  const source = extractFlatValue(b,
    'message[add][0][origin]',
    'unsorted[add][0][source]',
    'talk[update][0][origin]',
    'talk[add][0][origin]'
  );

  // استخراج وتطبيع التوقيت
  const rawTimestamp = extractFlatValue(b,
    'message[add][0][created_at]',
    'talk[add][0][created_at]',
    'talk[update][0][updated_at]',
    'unsorted[add][0][created_at]',
    'unsorted[add][0][source_data][date]',
    'leads[update][0][updated_at]'
  );

  const event_ts_unix = normalizeTimestamp(rawTimestamp);

  // إنشاء معرف فريد قوي
  const fingerprint = generateFingerprint({
    message_id,
    chat_id,
    lead_id,
    source,
    created_at: event_ts_unix,
    text_snippet: message_text,
    event_type: classification.event_type
  });

  debugLog("Generated fingerprint:", fingerprint);

  // التحقق من المعالجة السابقة
  if (message_id && staticData.processedMessages[message_id]) {
    debugLog("Message already processed, skipping");
    return;
  }

  // ==================
  // تجميع الأحداث
  // ==================

  // إنشاء أو تحديث المجموعة
  if (!eventGroups[fingerprint]) {
    eventGroups[fingerprint] = {
      events: [],
      pulses_received: 0,
      expected_pulses: classification.expected_pulses,
      lead_id: '',
      chat_id: '',
      message_text: '',
      message_id: '',
      client_name: '',
      pipeline_id: '',
      status_id: '',
      source: '',
      has_message: false,
      is_new_lead: false,
      is_complete: false,
      timestamp: event_ts_unix,
      first_pulse_time: Date.now(),
      last_pulse_time: Date.now(),
      unique_events: new Set()
    };
  }

  const group = eventGroups[fingerprint];

  // تحديث البيانات (فقط إذا كانت القيم الجديدة غير فارغة)
  group.pulses_received++;
  group.last_pulse_time = Date.now();
  group.unique_events.add(classification.event_type);

  if (lead_id) group.lead_id = lead_id;
  if (chat_id) group.chat_id = chat_id;
  if (message_text) group.message_text = message_text;
  if (message_id) group.message_id = message_id;
  if (client_name) group.client_name = client_name;
  if (pipeline_id) group.pipeline_id = pipeline_id;
  if (status_id) group.status_id = status_id;
  if (source) group.source = source;

  // تحديث الأعلام
  if (classification.event_type === 'message[add]' && message_text) {
    group.has_message = true;
  }
  if (classification.event_type === 'unsorted[add]') {
    group.is_new_lead = true;
  }

  // فحص اكتمال النبضات
  const timeSinceFirstPulse = Date.now() - group.first_pulse_time;
  if (group.pulses_received >= group.expected_pulses ||
      group.pulses_received >= CONFIG.MAX_EVENTS_PER_MESSAGE ||
      timeSinceFirstPulse > CONFIG.TIME_WINDOW * 1000) {
    group.is_complete = true;
    debugLog(`Group ${fingerprint} marked as complete`);
  }

  // حفظ في الكاش
  staticData.messageCache[fingerprint] = {
    ...group,
    unique_events_array: Array.from(group.unique_events),
    timestamp: Date.now()
  };
});

// ==================
// إنتاج النتائج النهائية
// ==================
const finalResults = [];

for (const [fingerprint, group] of Object.entries(eventGroups)) {
  // تحديد الإجراء المطلوب
  let action_required = 'log_only';
  let should_respond = false;

  if (group.has_message && group.message_text) {
    action_required = 'process_message';
    should_respond = true;
  } else if (group.is_new_lead && group.message_text) {
    action_required = 'process_new_lead_message';
    should_respond = true;
  } else if (group.is_new_lead) {
    action_required = 'welcome_new_lead';
    should_respond = true;
  } else if (!group.message_text && !group.is_new_lead) {
    // تجاهل الأحداث بدون محتوى مفيد
    action_required = 'ignore';
    should_respond = false;
  }

  // وضع علامة كمعالج
  if (group.message_id) {
    staticData.processedMessages[group.message_id] = Date.now();
  }

  const completeness_status = group.is_complete ? 'complete' : 'partial';
  const completeness_percentage = Math.min(100, 
    Math.round((group.pulses_received / group.expected_pulses) * 100));

  let confidence_level = 'low';
  if (completeness_percentage >= 90) {
    confidence_level = 'high';
  } else if (completeness_percentage >= 70) {
    confidence_level = 'medium';
  }

  // تحديد نوع الخدمة
  let service_type = 'general';
  if (group.pipeline_id) {
    const pipelineMap = {
      '10794139': 'sales',
      '1234': 'support',
      '5678': 'onboarding'
    };
    service_type = pipelineMap[group.pipeline_id] || 'general';
  }

  debugLog(`\n=== Final Result for ${fingerprint} ===`);
  debugLog("Message text:", group.message_text || "EMPTY");
  debugLog("Action required:", action_required);
  debugLog("Completeness:", `${completeness_percentage}%`);

  // إضافة النتيجة فقط إذا كانت ذات قيمة
  if (action_required !== 'ignore' || group.message_text || group.lead_id) {
    finalResults.push({
      json: {
        // معرفات أساسية
        group_key: fingerprint,
        message_fingerprint: fingerprint,
        lead_id: group.lead_id || '',
        chat_id: group.chat_id || '',
        message_id: group.message_id || '',

        // بيانات الرسالة
        message_text: group.message_text || '',
        client_name: group.client_name || '',

        // معلومات Pipeline
        pipeline_id: group.pipeline_id || '',
        status_id: group.status_id || '',
        source: group.source || '',

        // معلومات المعالجة
        action_required,
        should_respond,
        has_message: group.has_message,
        is_new_lead: group.is_new_lead,

        // إحصائيات النبضات
        pulses_received: group.pulses_received,
        expected_pulses: group.expected_pulses,
        completeness_status,
        completeness_percentage,
        is_complete: group.is_complete,
        confidence_level,

        // معلومات الخدمة
        service_type,
        requires_human: confidence_level === 'low' || !group.message_text,

        // التوقيتات
        event_time_utc: group.timestamp ? 
          new Date(Number(group.timestamp) * 1000).toISOString() : 
          new Date().toISOString(),
        received_at_utc: new Date().toISOString(),
        aggregation_time_ms: group.last_pulse_time - group.first_pulse_time,
        processing_time_ms: Date.now() - group.first_pulse_time,

        // معلومات إضافية
        unique_event_types: Array.from(group.unique_events).join(', '),
        processed: true,
        ready_for_processing: true,
        deduplication_count: 1,

        // معلومات debug
        cache_size: staticData.cacheSize || Object.keys(staticData.messageCache).length,
        has_valid_content: !!(group.message_text || group.is_new_lead)
      }
    });
  }
}

debugLog(`\n=== Processing Complete ===`);
debugLog(`Total results: ${finalResults.length}`);
debugLog(`Cache size: ${Object.keys(staticData.messageCache).length}`);

return finalResults;

// التحقق من اكتمال الرسالة وإعادة التجميع النهائي
// ================================================
// Version: 2.0 - محدث لتصفية البيانات الفارغة

const staticData = $getWorkflowStaticData('global');
const messageGroups = {};

// تجميع كل الرسائل حسب fingerprint
items.forEach(item => {
  const fingerprint = item.json.message_fingerprint;

  if (!messageGroups[fingerprint]) {
    messageGroups[fingerprint] = {
      items: [],
      total_pulses: 0,
      latest_data: null,
      highest_priority: null
    };
  }

  messageGroups[fingerprint].items.push(item);
  messageGroups[fingerprint].total_pulses += item.json.pulses_received || 1;

  // احتفظ بأحدث البيانات
  if (!messageGroups[fingerprint].latest_data || 
      item.json.pulses_received > messageGroups[fingerprint].latest_data.pulses_received) {
    messageGroups[fingerprint].latest_data = item.json;
  }
});

// إرجاع رسالة واحدة فقط لكل مجموعة
const finalMessages = [];

for (const [fingerprint, group] of Object.entries(messageGroups)) {
  const data = group.latest_data;

  // تحديث حالة الاكتمال
  const completeness_percentage = Math.min(100, 
    Math.round((group.total_pulses / (data.expected_pulses || 1)) * 100));

  // تحديد مستوى الثقة
  let confidence_level = 'low';
  if (completeness_percentage >= 90) {
    confidence_level = 'high';
  } else if (completeness_percentage >= 70) {
    confidence_level = 'medium';
  }

  // تحديد نوع الخدمة بناءً على Pipeline/Stage
  let service_type = 'general';
  if (data.pipeline_id) {
    const pipelineMap = {
      '10794139': 'sales',
      '1234': 'support',
      '5678': 'onboarding'
    };
    service_type = pipelineMap[data.pipeline_id] || 'general';
  }

  // التحقق من صلاحية البيانات
  const hasValidContent = !!(
    data.message_text || 
    data.is_new_lead || 
    (data.lead_id && data.action_required !== 'ignore')
  );

  // تصفية الأحداث الفارغة أو غير المفيدة
  if (!hasValidContent && data.action_required === 'log_only' && !data.message_text) {
    console.log(`Skipping empty event: ${fingerprint}`);
    // تنظيف من الذاكرة المؤقتة
    if (staticData.messageCache && staticData.messageCache[fingerprint]) {
      delete staticData.messageCache[fingerprint];
    }
    continue; // تجاهل هذا الحدث
  }

  // إضافة النتيجة النهائية
  finalMessages.push({
    json: {
      ...data,

      // معلومات الاكتمال
      final_pulse_count: group.total_pulses,
      completeness_percentage,
      confidence_level,

      // معلومات الخدمة
      service_type,
      requires_human: confidence_level === 'low' || !data.message_text,

      // توقيت المعالجة
      aggregation_completed_at: new Date().toISOString(),
      processing_time_ms: Date.now() - new Date(data.received_at_utc).getTime(),

      // حالة نهائية
      ready_for_processing: true,
      deduplication_count: group.items.length,
      has_valid_content: hasValidContent,

      // تنظيف البيانات الفارغة
      message_text: data.message_text || '',
      client_name: data.client_name || 'Unknown',
      action_required: data.action_required || 'none'
    }
  });

  // تنظيف من الذاكرة المؤقتة
  if (staticData.messageCache && staticData.messageCache[fingerprint]) {
    delete staticData.messageCache[fingerprint];
  }
}

console.log(`Final messages count: ${finalMessages.length}`);
return finalMessages;

// In: items[].json.body (Kommo webhook) or whole item.json
// Out: { raw, received_at }
return items.map(it => {
  const raw = it.json?.body ? it.json.body : (it.json || {});
  return { json: { raw, received_at: Date.now() } };
});

// Helpers (صغيرة ومكررة هنا لاستقلال النود)
const CONFIG = { MAX_EVENTS_PER_MESSAGE: 10 };
function g(b,p,f=''){ if(!b||!p) return f; if(p.includes('[')) return b[p] ?? f;
  try{ return p.split('.').reduce((o,k)=>(o&&k in o)?o[k]:undefined,b) ?? f; }catch{ return f; } }
function extractFlatValue(o,...keys){ for(const k of keys){ const v=g(o,k);
  if(v!==undefined&&v!==null&&v!==''){ if(typeof v==='string'){ const s=v.trim();
    if(s && !s.includes('infodvnlog') && !s.includes('.com')) return s; } else return v; } } return ''; }
function classifyEvent(body){ const ks=Object.keys(body||{}); const has=p=>ks.some(k=>k.startsWith(p));
  const T=[ ['message[add]',10,'message',9], ['unsorted[add]',8,'lead_creation',6], ['talk[add]',6,'conversation',4],
            ['talk[update]',5,'conversation',4], ['leads[update]',4,'lead_management',3], ['leads[delete]',1,'deletion',1],
            ['contacts[update]',3,'contact_management',2], ['contacts[add]',2,'contact_management',2] ];
