function extractFlatValue(o,...keys){ for(const k of keys){ const v=g(o,k);
  if(v!==undefined&&v!==null&&v!==''){ if(typeof v==='string'){ const s=v.trim();
    if(s && !s.includes('infodvnlog') && !s.includes('.com')) return s; } else return v; } } return ''; }
function extractTags(body){ const tags=new Set();
  const paths=['leads[update][0][tags]','leads[add][0][tags]','unsorted[add][0][tags]','contacts[update][0][tags]',
               'leads[update][0][_embedded][tags]','talk[update][0][tags]','talk[add][0][tags]'];
  for(const p of paths){ const v=g(body,p); if(!v) continue;
    if(typeof v==='string') v.split(',').map(t=>t.trim().toLowerCase()).forEach(t=>t&&tags.add(t));
    else if(Array.isArray(v)) v.forEach(x=> typeof x==='string'? tags.add(x.toLowerCase()): (x?.name && tags.add(String(x.name).toLowerCase()))); }
  Object.keys(body).forEach(k=>{ if(k.includes('[tags][')||k.includes('[tag][')){ const v=body[k]; if(typeof v==='string') tags.add(v.toLowerCase()); }});
  return Array.from(tags); }
function extractPipelineStageInfo(body){
