function extractMessageText(body,eventType){
  let text=''; const paths=[
    'talk[update][0][last_message_text]','talk[update][0][messages][0][text]','talk[update][0][last_message][text]','talk[update][0][text]','talk[add][0][text]',
    'message[add][0][text]','message[add][0][message]','message[add][0][body]','message[add][0][content]',
    'unsorted[add][0][source_data][data][0][text]','unsorted[add][0][text]',
    'leads[update][0][last_message]','leads[update][0][notes][0][text]','leads[update][0][custom_fields_values][0][values][0][value]',
    'contacts[update][0][last_message]','contacts[add][0][note]'
  ];
  for(const p of paths){ const v=g(body,p); if(typeof v==='string' && v.trim() && !v.includes('http') && !v.includes('infodvnlog') && !v.includes('.com')){ text=v.trim(); break; } }
  if(!text){
    // sweep notes/messages
    for(let i=0;i<20 && !text;i++){
      for(const p of [
        `leads[update][0][notes][${i}][text]`,
        `talk[update][0][messages][${i}][text]`,
        `talk[update][0][messages][${i}][content]`
      ]){ const v=g(body,p); if(typeof v==='string' && v.trim()){ text=v.trim(); break; } }
    }
  }
  if(!text){
    // deep JSON
    const search=(o,d=0)=>{ if(d>7||!o||typeof o!=='object') return '';
      for(const [k,v] of Object.entries(o)){
        const kk=String(k).toLowerCase();
        if(['text','message','body','content','note','last_message','last_message_text','value'].includes(kk) && typeof v==='string' && v.trim() && !v.includes('http') && !v.includes('infodvnlog') && !v.includes('.com')) return v.trim();
        if(typeof v==='object'){ const n=search(v,d+1); if(n) return n; }
      } return ''; };
    text = search(body);
  }
  return text;
}

